def decide(g,m):
    if m["recurrent_top1_guard_weakened"]: return "top1_guard_invariant_violation","D99G_TOP1_GUARD_REPAIR"
    if m["recurrent_D68_preservation_rate"]<1.0: return "d68_regression_detected","D99D_D68_REGRESSION_REPAIR"
    if not m["recurrent_truth_leak_audit_passed"] or not m["recurrent_oracle_isolation_passed"]: return "d99_truth_leak_or_oracle_contamination_detected","D99L_TRUTH_LEAK_REPAIR"
    if not g["sentinel_collapse_passed"] or m["forbidden_feature_detected"]: return "d99_shortcut_memorization_detected","D99H_SHORTCUT_MEMORIZATION_REPAIR"
    if not m["split_integrity_passed"] or m["train_test_ood_contamination_detected"]: return "d99_split_contamination_detected","D99S_SPLIT_INTEGRITY_REPAIR"
    if m["fallback_rows"]>0: return "d99_rust_fallback_detected","D99R_RUST_PATH_REPAIR"
    failed=[k for k,v in g.items() if not v]
    utility=["recurrent_state_ablation_delta","recurrent_shuffled_state_delta","recurrent_one_step_ablation_delta","recurrent_no_state_control_delta","recurrent_loop_usefulness_score","recurrent_loop_usefulness_on_tail_score"]
    if any(k in failed for k in utility): return "d99_recurrent_loop_utility_not_confirmed","D99U_LOOP_UTILITY_REPAIR"
    if any(k in failed for k in ["recurrent_state_noise_1pct_accuracy","recurrent_state_noise_3pct_accuracy","recurrent_state_noise_5pct_accuracy","recurrent_state_reset_recovery_accuracy"]): return "d99_recurrent_state_robustness_failure","D99F_STATE_ROBUSTNESS_REPAIR"
    if any(k in failed for k in ["recurrent_worst_seed_accuracy","worst_tail_failure_rate","mixed_tail_compound_failure_rate"]): return "d99_recurrent_tail_risk_detected","D99T_RECURRENT_TAIL_RISK_REPAIR"
    if "false_positive_confidence_tail_rate" in failed or "recurrent_halting_false_positive_rate" in failed: return "d99_recurrent_calibration_failure","D99C_CALIBRATION_REPAIR"
    if failed: return "d99_invalid_metric_or_report_inconsistency","D99_REPORTING_REPAIR"
    return "d99_recurrent_routing_microcircuit_prototype_confirmed","D100_RECURRENT_ROUTING_MICROCIRCUIT_SCALE_CONFIRM"

