def write_report(out,decision,m,scale):
    lines=[f"# {TASK}","","D99 prototypes an explicit recurrent routing microcircuit using allowed inference-time non-truth features only.","",f"- decision: `{decision['decision']}`",f"- next: `{decision['next']}`",f"- best fair recurrent arm: `{m['best_fair_recurrent_arm']}`",f"- test/OOD/stress/min/worst: `{m['recurrent_test_accuracy']}` / `{m['recurrent_ood_accuracy']}` / `{m['recurrent_stress_accuracy']}` / `{m['recurrent_min_seed_accuracy']}` / `{m['recurrent_worst_seed_accuracy']}`",f"- convergence/non-convergence/oscillation: `{m['recurrent_convergence_rate']}` / `{m['recurrent_non_convergence_rate']}` / `{m['recurrent_oscillation_rate']}`",f"- loop usefulness: `{m['recurrent_loop_usefulness_score']}` tail `{m['recurrent_loop_usefulness_on_tail_score']}`","","## Boundary","",BOUNDARY,""]
    (out/"report.md").write_text("\n".join(lines),encoding="utf-8")

