    out=Path(args.out); out.mkdir(parents=True,exist_ok=True); write_json(out/"queue.json",{"task":TASK,"created_at":round(time.time(),3),"seeds":parse_seeds(args.seeds),"rows_per_seed":{"train":args.train_rows_per_seed,"test":args.test_rows_per_seed,"ood":args.ood_rows_per_seed},"stress_seeds":parse_seeds(args.stress_seeds),"stress_rows_per_seed":args.stress_rows_per_seed,"stress_modes":STRESS_MODES,"workers":args.workers,"cpu_target":args.cpu_target,"heartbeat_sec":args.heartbeat_sec}); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"phase0","message":"starting D99 D98 upstream audit"})
    restore=ensure_d98(args); write_json(out/"artifact_restore_report.json",restore); manifest=d98_manifest(restore); write_json(out/"d98_upstream_manifest.json",manifest); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"run","message":"building D99 recurrent microcircuit reports"}); agg,dec=build_reports(args,out,manifest); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"complete","decision":dec["decision"]})
    m=agg["metrics"]; print(json.dumps({"task":TASK,"out":str(out),"decision":dec["decision"],"next":dec["next"],"best_fair_recurrent_arm":m["best_fair_recurrent_arm"],"recurrent_test_accuracy":m["recurrent_test_accuracy"],"failed_jobs":m["failed_jobs"]},indent=2))
